mapper.sql:
where deleted = 0
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')

    and (memory_title like concat('%', #{keyword}, '%')
         or memory_summary like concat('%', #{keyword}, '%'))


    and memory_type = #{memoryType}

mapper.select:
select count(1)
from ai_user_memory
where deleted = 0
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')
  and memory_type = #{memoryType}
  and memory_summary = #{memorySummary}

mapper.update:
update ai_user_memory
set deleted = 1, updated_at = current_timestamp
where id = #{id}
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')
